<?php
namespace Tests\App\Controllers;use CodeIgniter\Test\CIUnitTestCase;use CodeIgniter\Test\FeatureTestTrait;
class AccountingJournalsTest extends CIUnitTestCase{use FeatureTestTrait;public function testQuickJournalPostInsertsEntryAndLines(){ $db=\Config\Database::connect('accounting');$db->query("INSERT IGNORE INTO accounts(code,name,type) VALUES ('T100','Test Asset','Asset'),('T200','Test Expense','Expense')");$accs=$db->query("SELECT id FROM accounts WHERE code IN ('T100','T200') ORDER BY code")->getResultArray();$this->assertCount(2,$accs,'Test accounts not seeded');$debitId=(int)$accs[0]['id'];$creditId=(int)$accs[1]['id'];$date=date('Y-m-d');$memo='JUnit Quick Post';$amount=123.45;$result=$this->post('/accounting/journals/quick',['entry_date'=>$date,'memo'=>$memo,'account_debit'=>$debitId,'account_credit'=>$creditId,'amount'=>$amount]);$result->assertRedirect();$entryRow=$db->query("SELECT * FROM journal_entries ORDER BY id DESC LIMIT 1")->getRowArray();$this->assertNotEmpty($entryRow,'No journal entry inserted');$this->assertEquals($amount,(float)$entryRow['total_debits']);$this->assertEquals($amount,(float)$entryRow['total_credits']);$lines=$db->query("SELECT * FROM journal_lines WHERE entry_id = ?",[$entryRow['id']])->getResultArray();$this->assertCount(2,$lines,'Expected two journal lines');$debits=array_sum(array_map(fn($l)=>(float)$l['debit'],$lines));$credits=array_sum(array_map(fn($l)=>(float)$l['credit'],$lines));$this->assertEquals($amount,$debits,'Debit total mismatch');$this->assertEquals($amount,$credits,'Credit total mismatch');}}
